  1→################################################################################
  2→# ClickHouse Data Bucket (S3 backend)
  3→################################################################################
  4→
  5→resource "aws_s3_bucket" "data" {
  6→  bucket = "${local.name_prefix}-data-${data.aws_caller_identity.current.account_id}"
  7→}
  8→
  9→resource "aws_s3_bucket_public_access_block" "data" {
 10→  bucket = aws_s3_bucket.data.id
 11→
 12→  block_public_acls       = true
 13→  block_public_policy     = true
 14→  ignore_public_acls      = true
 15→  restrict_public_buckets = true
 16→}
 17→
 18→resource "aws_s3_bucket_server_side_encryption_configuration" "data" {
 19→  bucket = aws_s3_bucket.data.id
 20→
 21→  rule {
 22→    apply_server_side_encryption_by_default {
 23→      sse_algorithm = "aws:kms"
 24→    }
 25→    bucket_key_enabled = true
 26→  }
 27→}
 28→
 29→resource "aws_s3_bucket_versioning" "data" {
 30→  bucket = aws_s3_bucket.data.id
 31→  versioning_configuration {
 32→    status = "Disabled"
 33→  }
 34→}
 35→
 36→resource "aws_s3_bucket_intelligent_tiering_configuration" "data" {
 37→  bucket = aws_s3_bucket.data.id
 38→  name   = "entire-bucket"
 39→
 40→  tiering {
 41→    access_tier = "ARCHIVE_ACCESS"
 42→    days        = 90
 43→  }
 44→}
 45→
 46→resource "aws_s3_bucket_lifecycle_configuration" "data" {
 47→  bucket = aws_s3_bucket.data.id
 48→
 49→  rule {
 50→    id     = "transition-to-intelligent-tiering"
 51→    status = "Enabled"
 52→    filter {}
 53→
 54→    transition {
 55→      days          = 0
 56→      storage_class = "INTELLIGENT_TIERING"
 57→    }
 58→  }
 59→}
 60→
 61→resource "aws_s3_bucket_policy" "data" {
 62→  bucket = aws_s3_bucket.data.id
 63→  policy = data.aws_iam_policy_document.data_bucket_policy.json
 64→}
 65→
 66→data "aws_iam_policy_document" "data_bucket_policy" {
 67→  statement {
 68→    sid    = "AllowClickHouseTaskRole"
 69→    effect = "Allow"
 70→    principals {
 71→      type        = "AWS"
 72→      identifiers = [aws_iam_role.ecs_task.arn]
 73→    }
 74→    actions = [
 75→      "s3:GetObject",
 76→      "s3:PutObject",
 77→      "s3:DeleteObject",
 78→      "s3:ListBucket",
 79→      "s3:GetBucketLocation",
 80→    ]
 81→    resources = [
 82→      aws_s3_bucket.data.arn,
 83→      "${aws_s3_bucket.data.arn}/*",
 84→    ]
 85→  }
 86→}
 87→
 88→################################################################################
 89→# Log Bucket
 90→################################################################################
 91→
 92→resource "aws_s3_bucket" "logs" {
 93→  bucket = "${local.name_prefix}-logs-${data.aws_caller_identity.current.account_id}"
 94→}
 95→
 96→resource "aws_s3_bucket_public_access_block" "logs" {
 97→  bucket = aws_s3_bucket.logs.id
 98→
 99→  block_public_acls       = true
100→  block_public_policy     = true
101→  ignore_public_acls      = true
102→  restrict_public_buckets = true
103→}
104→
105→resource "aws_s3_bucket_policy" "logs" {
106→  bucket = aws_s3_bucket.logs.id
107→  policy = data.aws_iam_policy_document.logs_bucket_policy.json
108→}
109→
110→data "aws_iam_policy_document" "logs_bucket_policy" {
111→  statement {
112→    sid    = "AllowALBAccessLogs"
113→    effect = "Allow"
114→    principals {
115→      type        = "Service"
116→      identifiers = ["logdelivery.elasticloadbalancing.amazonaws.com"]
117→    }
118→    actions   = ["s3:PutObject"]
119→    resources = ["${aws_s3_bucket.logs.arn}/alb/*"]
120→    condition {
121→      test     = "StringEquals"
122→      variable = "s3:x-amz-acl"
123→      values   = ["bucket-owner-full-control"]
124→    }
125→  }
126→}
127→
128→resource "aws_s3_bucket_server_side_encryption_configuration" "logs" {
129→  bucket = aws_s3_bucket.logs.id
130→
131→  rule {
132→    apply_server_side_encryption_by_default {
133→      sse_algorithm = "AES256"
134→    }
135→  }
136→}
137→
138→resource "aws_s3_bucket_lifecycle_configuration" "logs" {
139→  bucket = aws_s3_bucket.logs.id
140→
141→  rule {
142→    id     = "expire-old-logs"
143→    status = "Enabled"
144→    filter {}
145→
146→    expiration {
147→      days = 90
148→    }
149→  }
150→}
